/** ID: AR70044.01 Name: arcust_ins_upd Owner: ZA ScriptDate: 04/15/2013 **/
CREATE trigger [dbo].[arcust_ins_upd] on [dbo].[arcust]
for insert, update
as
begin
    if exists (select lexcl from cosyst where lexcl = 1)   /* exclusive mode */
       return

    DECLARE @laccept INT
    set xact_abort on
    if exists (select ccustno from inserted) and not exists(select ccustno from deleted)
		begin
			update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			SELECT @laccept=laccept from inserted	
			IF @laccept=1
				update arcust set daccept=GETDATE() WHERE ccustno = (select ccustno from inserted);

		end
	else
		begin
			if update(laccept) and (select laccept from inserted) <> (select laccept from deleted)
			begin
				SELECT @laccept=laccept from inserted	
				IF @laccept=1
					update arcust set daccept=GETDATE() WHERE ccustno = (select ccustno from inserted);
				ELSE
					update arcust set daccept=NULL WHERE ccustno = (select ccustno from inserted);
			end
			if update(cEmail) and (select cEmail from inserted) <> (select cEmail from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cStatus) and (select cStatus from inserted) <> (select cStatus from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(lApplyTax) and (select lApplyTax from inserted) <> (select lApplyTax from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cTaxCode) and (select cTaxCode from inserted) <> (select cTaxCode from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cCompany) and (select cCompany from inserted) <> (select cCompany from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(caddr1) and (select caddr1 from inserted) <> (select caddr1 from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(caddr2) and (select caddr2 from inserted) <> (select caddr2 from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(ccity) and (select ccity from inserted) <> (select ccity from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cstate) and (select cstate from inserted) <> (select cstate from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(czip) and (select czip from inserted) <> (select czip from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cCountry) and (select cCountry from inserted) <> (select cCountry from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cFname) and (select cFname from inserted) <> (select cFname from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cLname) and (select cLname from inserted) <> (select cLname from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cBilltono) and (select cBilltono from inserted) <> (select cBilltono from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cshiptono) and (select cshiptono from inserted) <> (select cshiptono from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cGender) and (select cGender from inserted) <> (select cGender from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cIdno) and (select cIdno from inserted) <> (select cIdno from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cPhone1) and (select cPhone1 from inserted) <> (select cPhone1 from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			if update(cfax) and (select cfax from inserted) <> (select cfax from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)	
		    if update(liocust) and (select liocust from inserted) <> (select liocust from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)		
			 if update(lrsa) and (select lrsa from inserted) <> (select lrsa from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)	
			 if update(cNation) and (select cNation from inserted) <> (select cNation from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)		
			 if update(cmarstat) and (select cmarstat from inserted) <> (select cmarstat from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)		
			 if update(cpfirstname) and (select cpfirstname from inserted) <> (select cpfirstname from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)		
			 if update(cpname) and (select cpname from inserted) <> (select cpname from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)		
			 if update(cpcell) and (select cpcell from inserted) <> (select cpcell from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)		
			 if update(cphone3) and (select cphone3 from inserted) <> (select cphone3 from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)		
			 if update(cpemail) and (select cpemail from inserted) <> (select cpemail from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)		
			 if update(cfacebook) and (select cfacebook from inserted) <> (select cfacebook from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)		
			 if update(ctwitter) and (select ctwitter from inserted) <> (select ctwitter from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)											
			 if update(laccept) and (select laccept from inserted) <> (select laccept from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)		
			 if update(clanguage) and (select clanguage from inserted) <> (select clanguage from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)
			 if update(daccept) and (select daccept from inserted) <> (select daccept from deleted)
				update arcust set lUpdatePortal = 1 where ccustno = (select ccustno from inserted)		

		end
end


