/* infotrac h.l. 15-oct-2004 update modified time stamp on iciitem (not iciwhs) */
CREATE trigger [dbo].[iciwhs_checkaa0005114] on [dbo].[iciwhs]
for update
as
begin
  if @@rowcount = 0 return


  declare @lcitemno char(20),@lcDescript CHAR(54),@cMessage CHAR(200)
  if not exists(select 1 from inserted where citemno IN('AA/00080/14','AA/00123/16') and cwarehouse='4400') return

  if not exists(select 1 from inserted where (nonhand-nbook)<100) return

  SET @cMessage='Below 100' 
EXEC	Compsys.[dbo].[sp_Sendmail]
		@lcSubject = N'0649064709',
		@lcMessage = @cMessage,
		@lcFrom = N'Trigger',
		@lcTo = N'SMS',
		@lcc =''


end

