/** ID: IC90085.01 Name: ictrsn_insert Owner: AM ScriptDate: 03/07/2014 **/
create trigger ictrsn_insert on ictrsn
for insert
as
begin
	/* -- new trigger -- */
	/* exclusive mode */
	if exists (select lexcl from cosyst where lexcl = 1)   
        return

	/* no cost and amt decimal difference */
	if exists (select 1 from cosyst where namtdec = ncodec)   
        return

	declare @lcuid varchar(15), @lnvariance numeric(18,10)

	/* compute for GL amount and variance */
	select  @lcuid = cuid, 
	        @lnvariance = isnull(ntotcost - round(ntotcost,(select isnull(namtdec, 0) from cosyst)), 0) 
	from inserted

	/* update ictrsn values */
	update ictrsn set ncostvar = @lnvariance
	where cuid = @lcuid 
end

/** ID: PO90006.01 Name: porecg_insert Owner: AM ScriptDate: 03/07/2014 **/
CREATE trigger [dbo].[porecg_insert] on [dbo].[porecg]
for insert
as
begin
    if exists (select lexcl from cosyst where lexcl = 1)   /* exclusive mode */
       return

    set xact_abort on
    declare @lcpono char(10), @lcrcptno char(10), @lcvendno char(10), @lcwarehouse char(10),
      @ldreceive datetime, @lnrecamt numeric(18,4), @lndiscamt numeric(18,4), @lnfrtamt numeric(18,4), 
      @lnfrecamt numeric(18,4), @lnfdiscamt numeric(18,4), @lnffrtamt numeric(18,4),
      @lntaxamt1 numeric(18,4), @lntaxamt2 numeric(18,4), @lntaxamt3 numeric(18,4),
      @lnftaxamt1 numeric(18,4), @lnftaxamt2 numeric(18,4), @lnftaxamt3 numeric(18,4),   
      @lctaxcode char(10), @lntaxver integer, @lnftaxamt numeric(18,4), @lntaxamt numeric(18,4), 
      @lnftrsamt numeric(18,4), @lntrsamt numeric(18,4),
      @lctaxtype char(1),
      @llaccrue smallint  

    execute vsp_am_settings @cvarname = 'ctaxtype', @cretvalue = @lctaxtype output   

    declare curporecg_ins scroll cursor for 
    select cpono, crcptno, cvendno, cwarehouse, dreceive, 
      nrecamt, ndiscamt, nfrtamt, ntaxamt1, ntaxamt2, ntaxamt3, 
      nfrecamt, nfdiscamt, nffrtamt, nftaxamt1, nftaxamt2, nftaxamt3,
      ctaxcode, ntaxver
    from inserted
    open curporecg_ins
    fetch next from curporecg_ins 
    into @lcpono, @lcrcptno, @lcvendno, @lcwarehouse, @ldreceive,
      @lnrecamt, @lndiscamt, @lnfrtamt, @lntaxamt1, @lntaxamt2, @lntaxamt3,
      @lnfrecamt, @lnfdiscamt, @lnffrtamt, @lnftaxamt1, @lnftaxamt2, @lnftaxamt3,
      @lctaxcode, @lntaxver
    while @@fetch_status = 0   
    begin
        update popord
        set nfrtamtchg = nfrtamtchg + @lnfrtamt, nffrtamtch = nffrtamtch + @lnffrtamt
        where cpono = @lcpono

		--Rhe--
		if @lcpono like '%N%' OR @lcpono like '%T%'
		begin
			--UPDATE Sosord SET lHold=0 WHERE csono=@lcpono
			declare @cMessage CHAR(200)
		    SET @cMessage='Reward Order Received ' + @lcPono
			EXEC	Compsys.[dbo].[sp_Sendmail]
			@lcSubject = @cMessage,
			@lcMessage = @cMessage,
			@lcFrom = N'Trigger',
			@lcTo = N'shona@annique.com,jeanri@annique.com',
			@lcc =''


		end



        if (select lmatch from popord where cpono = @lcpono) = 1  
            begin
                declare @lcnewuid char(15), @lcglacc char(30), @lcglacc1 char(30),
                    @lcglacc2 char(30), @lcglacc3 char(30)

                select @lnftaxamt = @lnftaxamt1 + @lnftaxamt2 +  @lnftaxamt3,
                  @lntaxamt = @lntaxamt1 + @lntaxamt2 + @lntaxamt3
                /* Reset tax amount since it's included in line item */
                if @lctaxtype = 'L'
                    select @lnftaxamt = 0, @lntaxamt = 0

                execute vsp_am_assignuid @cretvalue = @lcnewuid output, @bfromfront = 0

                select @lnftrsamt = @lnfrecamt - @lnfdiscamt + @lnffrtamt + @lnftaxamt, 
                  @lntrsamt = @lnrecamt - @lndiscamt + @lnfrtamt + @lntaxamt

				select @llaccrue = laccrue from popord where cpono = @lcpono   
	        	if @llaccrue = 1   
					begin   
		                select @lcglacc = (select caccrecacc from apsyst)

		                insert into podist (cuid, cpono, crcptno, cvendno, 
		                  cglacc, ctrs, dtrs, nfamount, namount)
		                values (@lcnewuid, @lcpono, @lcrcptno, @lcvendno, 
		                  @lcglacc, 'A', @ldreceive, -@lnftrsamt, -@lntrsamt)
					end   

                execute vsp_po_accrue_amt @cuid = @lcnewuid, @cvendno = @lcvendno, 
                  @cpono = @lcpono, @crcptno = @lcrcptno, @cwarehouse = @lcwarehouse, 
                  @dtrs = @ldreceive, @nftrsamt = @lnftrsamt, @ntrsamt = @lntrsamt,
			      @laccrue = @llaccrue    

                if @lnffrtamt > 0
                    begin
			        	if @llaccrue = 1   
							begin   
		                        select @lcglacc = (select cfcstacc from apsyst)  
		                        execute vsp_am_assignuid @cretvalue = @lcnewuid output, @bfromfront = 0
		                        insert into podist (cuid, cpono, crcptno, cvendno,   
		                          cglacc, ctrs, dtrs, nfamount, namount)  
		                        values (@lcnewuid, @lcpono, @lcrcptno, @lcvendno,   
		                          @lcglacc, 'C', @ldreceive, @lnffrtamt, @lnfrtamt)  
		   					end  
	                        execute vsp_po_accrue_qty @cuid = @lcnewuid, @cvendno = @lcvendno,   
	                          @cpono = @lcpono, @crcptno = @lcrcptno, @cwarehouse = @lcwarehouse,   
	                          @ctype = 'FRGT', @dtrs = @ldreceive, @ntrsqty = 1,  
	                          @nftrsamt = @lnffrtamt, @ntrsamt = @lnfrtamt,
							  @laccrue = @llaccrue   
                    end

                if @lnftaxamt > 0   
                    begin
                        /* Get the tax account for each entity */
                        select @lcglacc1 = cptaxacc1, @lcglacc2 = cptaxacc2, @lcglacc3 = cptaxacc3
                        from costax
                        where ctaxcode = @lctaxcode and nversion = @lntaxver
                        execute vsp_am_assignuid @cretvalue = @lcnewuid output, @bfromfront = 0

						if @llaccrue = 1   
							begin
		                    	/* Tax Entity 1 */
		                        if @lnftaxamt1 > 0
                                    begin
		                                insert into podist (cuid, cpono, crcptno, cvendno,   
		                                  cglacc, ctrs, dtrs, nfamount, namount)  
		                                values (@lcnewuid, @lcpono, @lcrcptno, @lcvendno,   
		                                  @lcglacc1, 'T', @ldreceive, @lnftaxamt1, @lntaxamt1)
                                    end
		                        /* Tax Entity 2 */
		                        if @lnftaxamt2 > 0
		                            begin
		                                execute vsp_am_assignuid @cretvalue = @lcnewuid output, @bfromfront = 0    
		                                insert into podist (cuid, cpono, crcptno, cvendno,   
		                                  cglacc, ctrs, dtrs, nfamount, namount)  
		                                values (@lcnewuid, @lcpono, @lcrcptno, @lcvendno,   
		                                  @lcglacc2, 'T', @ldreceive, @lnftaxamt2, @lntaxamt2)
		                            end
		                        /* Tax Entity 3 */
		                        if @lnftaxamt3 > 0
		                            begin  
		                                execute vsp_am_assignuid @cretvalue = @lcnewuid output, @bfromfront = 0  
		                                insert into podist (cuid, cpono, crcptno, cvendno,   
		                                  cglacc, ctrs, dtrs, nfamount, namount)  
		                                values (@lcnewuid, @lcpono, @lcrcptno, @lcvendno,   
		                                  @lcglacc3, 'T', @ldreceive, @lnftaxamt3, @lntaxamt3)
		                            end
							end   
                        execute vsp_po_accrue_qty @cuid = @lcnewuid, @cvendno = @lcvendno,   
                          @cpono = @lcpono, @crcptno = @lcrcptno, @cwarehouse = @lcwarehouse,   
                          @ctype = 'PTAX', @dtrs = @ldreceive, @ntrsqty = 1,  
                          @nftrsamt = @lnftaxamt, @ntrsamt = @lntaxamt,
						  @laccrue = @llaccrue   
                    end
            end   /* accrue rec goods */
        fetch next from curporecg_ins 
        into @lcpono, @lcrcptno, @lcvendno, @lcwarehouse, @ldreceive,
          @lnrecamt, @lndiscamt, @lnfrtamt, @lntaxamt1, @lntaxamt2, @lntaxamt3, 
          @lnfrecamt, @lnfdiscamt, @lnffrtamt, @lnftaxamt1, @lnftaxamt2, @lnftaxamt3,
          @lctaxcode, @lntaxver
    end   
    close curporecg_ins
    deallocate curporecg_ins
end

/* infotrac h.l. 15-oct-2004 update modified time stamp on iciitem (not iciwhs) */
CREATE trigger [dbo].[wsLowStock_checkstockalert] on [dbo].[wsLowStock]
for insert,update
as
begin
  if @@rowcount = 0 return


  declare @citemno char(20),@lcDescript CHAR(54),@cMessage nVarChar(max),
  @minstockqty char(20),@StockQuantity char(20),@lUpdateonhand char(20),@nfrcsqty char(20),
  @nQtyLimit char(20),
	@cSponcat char(20),@cSponType char(20),@nOrdQty char(20),@nAvailable char(20),
	@ForcastAvail char(20),@AvailPercent char(20),@cStatus CHAR(20),@dDate char(20)

  SELECT @citemno=citemno,
  @minstockqty='Min Level:'+RTRIM(CAST(minstockqty AS CHAR(10))),
   @StockQuantity='Stock:'+RTRIM(CAST(stockQuantity AS CHAR(10))),
   @nfrcsqty = 'Forecast:'+RTRIM(CAST(nFrcsqty AS CHAR(10))),
   @nQtyLimit= 'Limit:'+RTRIM(CAST(nQtyLimit AS CHAR(10))),
   @cSponcat='Sponcat:'+RTRIM(cSponcat),
   @cSponType='SponType:'+RTRIM(cSpontype),
   @nOrdQty='Open Orders:'+RTRIM(CAST(nOrdQty AS CHAR(10))),
   @nAvailable='Available:'+RTRIM(CAST(nAvailable AS CHAR(10))),
   @ForcastAvail='FC Available:'+RTRIM(CAST(forcastAvail AS CHAR(10))),
   @AvailPercent='Avail %:'+RTRIM(CAST(AvailPercent AS CHAR(10))),
   @cStatus='Status:'+RTRIM(cStatus),
   @dDate=RTRIM(CAST(dDate AS CHAR(20)))
   FROM Inserted 

   select @lcDescript=cdescript from icitem WHERE citemno=@citemno

   SET @cMessage=RTRIM(@citemno)+  ' '+@lcDescript+' '+
    RTRIM(@cSponcat)+  ' '+RTRIM(@cSponType)+  ' '+
    RTRIM(@minstockqty)+  ' '+RTRIM(@StockQuantity)+  ' '+
	RTRIM(@nfrcsqty)+  ' '+
	RTRIM(@nQtyLimit)+  ' '+RTRIM(+@nOrdQty)+  ' '+RTRIM(@nAvailable)+  ' '+
	RTRIM(@ForcastAvail)+  ' '+RTRIM(@AvailPercent)+  ' '+
	RTRIM(@cStatus)+  ' '+@dDate

	--0649064709

EXEC	Compsys.[dbo].[sp_Sendmail]
		@lcSubject = N'0649064709',
		@lcMessage = @cMessage,
		@lcFrom = N'Trigger',
		@lcTo = N'SMS',
		@lcc =''
EXEC	Compsys.[dbo].[sp_Sendmail]
		@lcSubject = N'0725001666',
		@lcMessage = @cMessage,
		@lcFrom = N'Trigger',
		@lcTo = N'SMS',
		@lcc =''
EXEC	Compsys.[dbo].[sp_Sendmail]
		@lcSubject = N'0605045362',
		@lcMessage = @cMessage,
		@lcFrom = N'Trigger',
		@lcTo = N'SMS',
		@lcc =''

end
